// Strategy interface: all shipping calculators must follow this
interface ShippingStrategy {
  calculate(weightKg: number, distanceKm: number): number;
}
// Concrete strategy: Standard shipping ($0.50 per kg per 100km)
class StandardShipping implements ShippingStrategy {
  calculate(weightKg: number, distanceKm: number): number {
    return weightKg * 0.5 * (distanceKm / 100);
  }
}
// Concrete strategy: Express shipping (flat $20 + $1 per kg)
class ExpressShipping implements ShippingStrategy {
  calculate(weightKg: number, distanceKm: number): number {
    return 20 + weightKg * 1.0;
  }
}
// Context: uses a strategy without knowing its implementation
class ShippingCalculator {
  constructor(private strategy: ShippingStrategy) {}
  setStrategy(strategy: ShippingStrategy): void {
    this.strategy = strategy;
  }
  getCost(weightKg: number, distanceKm: number): number {
    return this.strategy.calculate(weightKg, distanceKm);
  }
}
const calc = new ShippingCalculator(new StandardShipping());
console.log('Standard:', calc.getCost(5, 200));
calc.setStrategy(new ExpressShipping());
console.log('Express:', calc.getCost(5, 200));
// Expected: Standard: 5, Express: 25
